"""
Parameterized generator for GH461_splinepy_482.

Source PR:    https://github.com/tataratat/splinepy/pull/482
Source Issue: N/A

Seed varies: renames 'addressed' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH461_splinepy_482'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH461_splinepy_482'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('addressed', 'addressed' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH461_splinepy_482',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'tataratat/splinepy',
                "pr_number": 482,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/tataratat/splinepy/pull/482",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            '.github/pull_request_template.md': '# Overview\nDescription\n\n## Addressed issues\n*  Issues addressed\n\n## Showcase\nA short / one-liner example to highlight the (new) feature\n```\nimport splinepy\n\nnew, feature = splinepy.tataratat()\n```\n\n## Checklists\n* [ ] Documentations are up-to-date.\n* [ ] Added example(s)\n* [ ] Added test(s)\n',
            'include/splinepy/py/py_multipatch.hpp': '/*\nMIT License\n\nCopyright (c) 2021 Jaewook Lee\n\nPermission is hereby granted, free of charge, to any person obtaining a copy\nof this software and associated documentation files (the "Software"), to deal\nin the Software without restriction, including without limitation the rights\nto use, copy, modify, merge, publish, distribute, sublicense, and/or sell\ncopies of the Software, and to permit persons to whom the Software is\nfurnished to do so, subject to the following conditions:\n\nThe above copyright notice and this permission notice shall be included in all\ncopies or substantial portions of the Software.\n\nTHE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\nIMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\nFITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE\nAUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER\nLIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,\nOUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN THE\nSOFTWARE.\n*/\n\n#pragma once\n\n#include <string>\n\n// pybind\n#include <pybind11/numpy.h>\n#include <pybind11/pybind11.h>\n\n//\n#include "splinepy/py/py_spline.hpp"\n#include "splinepy/utils/default_initialization_allocator.hpp"\n\nnamespace splinepy::py {\n\nnamespace py = pybind11;\n\n// alias for frequently used vectors\nusing CoreSplineVector =\n    std::vector<std::shared_ptr<splinepy::splines::SplinepyBase>>;\nusing IntVector = splinepy::utils::DefaultInitializationVector<int>;\nusing IntVectorVector = splinepy::utils::DefaultInitializationVector<IntVector>;\nusing DoubleVector = splinepy::utils::DefaultInitializationVector<double>;\n\n/// @brief Extracts CoreSpline from list of PySplines.\n/// @param pysplines\n/// @param nthreads\n/// @return\nstd::vector<PySpline::CoreSpline_> ToCoreSplineVector(py::list pysplines,\n                                                      const int nthreads = 1);\n\n/// @brief Overload to allow None entries. Will be filled with null spline\n/// @param pysplines\n/// @param para_dim_if_none\n/// @param dim_if_none\n/// @param nthreads\n/// @return\nstd::vector<PySpline::CoreSpline_>\nToCoreSplineVector(py::list pysplines,\n                   const int para_dim_if_none,\n                   const int dim_if_none,\n                   const int nthreads);\n\n/// @brief Converts a CoreSplineVector to a Python spline list\n/// @param splist\n/// @return py::list\npy::list ToPySplineList(CoreSplineVector& splist);\n\n/*\n * Sort Vector using lambda expressions\n * https://stackoverflow.com/a/12399290\n */\ntemplate<typename T>\nIntVector ArgSort(const std::vector<T>& v);\n\n/// @brief raises if there\'s any mismatch between specified properties and all\n/// the entries in the vector.\n/// @param splist\n/// @param name\n/// @param para_dim\n/// @param dim\n/// @param degrees\n/// @param control_mesh_resolutions\n/// @param nthreads\nvoid RaiseMismatch(const CoreSplineVector& splist,\n                   const std::string name,\n                   const int para_dim,\n                   const int dim,\n                   const IntVector& degrees,\n                   const IntVector& control_mesh_resolutions,\n                   const int nthreads);\n\n/// @brief raises if there\'s any mismatch between two given vectors of splines.\n/// @param splist0\n/// @param splist1\n/// @param name\n/// @param dimensionality\n/// @param field_dim\n/// @param degrees\n/// @param control_mesh_resolutions\n/// @param nthreads\nvoid RaiseMismatch(const CoreSplineVector& splist0,\n                   const CoreSplineVector& splist1,\n                   const bool name,\n                   const bool dimensionality,\n                   const int field_dim,\n                   const bool degrees,\n                   const bool control_mesh_resolutions,\n                   const int nthreads);\n\n/**\n * @brief Determine the connectivity from center-vertices, assuming nothing of\n * the underlying grid\n *\n * Duplicate Points are not eliminated, assuming that a maximum of two points\n * are equivalent. If this is not the case an exception is thrown. In theory\n * this has complexity O(nlogn) whereas a KDTree has complexity O(n (logn)^dim).\n *\n * @tparam PhysicalPointType Type of Point coordinates\n * @tparam ScalarType Type determining the precision\n * @tparam parametric_dimension dimension of the object (e.g. surface in 3D)\n * @tparam boolean check_orientation to check if neighboring elements match\n *                          structured grid\n * @param face_center_vertices vertices in the centers of spline-surfaces\n * @param parametric_dimension parametric dimension\n * @param metric used for preordering the vertices along a line\n * @param tolerance tolerance (distance between two vertices that are joined)\n\n * @return connectivity as a std::vector<std::array<...>>\n */\npy::array_t<int>\nFindConnectivityFromCenters(const py::array_t<double>& face_center_vertices,\n                            const int parametric_dimension,\n                            const py::array_t<double>& metric,\n                            const double tolerance);\n\n/**\n * @brief  Determines the Connectivity of spline patches\n *\n * @param py_center_vertices  Vertices in the center of the boundaries\n * @param tolerance tolerance between two neighboring face centers for them\n * to be fused\n * @param parametric_dimension Parametric dimension of the spline grid\n * @return py::array_t<int> connectivity\n */\npy::array_t<int>\nInterfacesFromBoundaryCenters(const py::array_t<double>& py_center_vertices,\n                              const double& tolerance,\n                              const int& parametric_dimension);\n\n/// @brief Orientation between two adjacent splines\n///\n/// If two splines share the same boundary this function retrieves their\n/// orientation, by mapping the mappings of the parametric axis onto each other.\n/// This is (among others) required for Gismo and Nutils export\n///\n/// @param pyspline_start Spline object from start\n/// @param boundary_start Boundary ID from start spline\n/// @param pyspline_end Spline object from end///to which is mapped\n/// @param boundary_end Boundary ID of adjacent spline\n/// @param tolerance Tolerance\n/// @param mappings_ptr (output) integer mappings\n/// @param orientations_ptr (output) axis alignment\nvoid GetInterfaceOrientation(\n    const std::shared_ptr<splinepy::splines::SplinepyBase>& pyspline_start,\n    const int& boundary_start,\n    const std::shared_ptr<splinepy::splines::SplinepyBase>& pyspline_end,\n    const int& boundary_end,\n    const double& tolerance,\n    int* mappings_ptr,\n    int* orientations_ptr);\n\n/// @brief Extract all Boundary Patches and store them in a python list\n///\n/// @param spline_list List of splines\n/// @param interfaces interfaces, with negative values for boundary elements\n/// @param n_threads Number of threads\n/// @return py::list\npy::list ExtractAllBoundarySplines(const py::list& spline_list,\n                                   const py::array_t<int>& interfaces,\n                                   const int& n_threads);\n\n/**\n * @brief  Adds a Boundary using a seed and G-continuity on boundary-splines\n *\n * This function might be a slight overkill, as it assigns all functions an ID,\n * even when previously assigned a different ID -> Future Project\n *\n * @param boundary_splines boundary patches\n * @param boundary_interfaces interfaces between boundary splines\n * @param global_interfaces global interfaces (in between "volume"-patches)\n * @param tolerance tolerance to be considered g1 (1 - cos(phi) < tolerance)\n * @param n_threads number of threads for parallel processing\n * @return int number of new boundaries\n */\nint AddBoundariesFromContinuity(const py::list& boundary_splines,\n                                const py::array_t<int>& boundary_interfaces,\n                                py::array_t<int>& global_interfaces,\n                                const double& tolerance,\n                                const int& n_threads);\n\n/// @brief Multi-patch splines. Here, use of the words\n///        "patch" and "spline" are interchangeable\nclass PyMultipatch {\npublic:\n  using CorePatches_ = std::vector<typename PySpline::CoreSpline_>;\n\n  /// individual patches, a.k.a. splines\n  py::list patches_;\n\n  /// casted, core splines (patches) from patches_ (list of PySpline).\n  CorePatches_ core_patches_;\n\n  /// sub patches - similar concept to subelement / face elements\n  std::shared_ptr<PyMultipatch> sub_multipatch_ = nullptr;\n\n  /// Casted sub multi patch\n  py::object py_sub_multipatch_ = py::none();\n\n  /// center of each sub patch.\n  py::array_t<double> sub_patch_centers_;\n\n  /// ids for boundary_patches from sub_patches_\n  py::array_t<int> boundary_patch_ids_;\n\n  /// Boundary multi patches. Should consist of one smaller parametric dim\n  std::shared_ptr<PyMultipatch> boundary_multipatch_ = nullptr;\n\n  /// Casted boundary multi patches\n  py::object py_boundary_multipatch_ = py::none();\n\n  /// patch-to-patch connectivity information\n  /// shape: (n_patches, n_boundary_elements)\n  py::array_t<int> interfaces_;\n\n  /// interface orientations that define mapping of parametric axis\n  py::array_t<int> interface_orientations_;\n\n  /// shape: (n_patches,)\n  py::array_t<int> boundary_ids_;\n\n  /// @brief Fields - they are saved as multi-patches\n  py::list field_multipatches_;\n\n  /// default number of threads for all the operations besides queries\n  int n_default_threads_{1};\n\n  /// hint flag that can be used to accelerate property decisions\n  bool same_parametric_bounds_{false};\n\n  /// internal flag to indicate that this a field multipatch that may contain\n  /// null spline\n  bool has_null_splines_{false};\n\n  /// default tolerance\n  double tolerance_{1e-11};\n\n  /// ctor\n  PyMultipatch() = default;\n\n  /// move ctor\n  PyMultipatch(PyMultipatch&& other) noexcept = default;\n\n  /// @brief list (iterable) init -> pybind will cast to list for us if needed\n  /// @param patches\n  /// @param n_default_threads\n  /// @param same_parametric_bounds\n  PyMultipatch(py::list& patches,\n               const int n_default_threads = 1,\n               const bool same_parametric_bounds = false)\n      : n_default_threads_(n_default_threads),\n        same_parametric_bounds_(same_parametric_bounds) {\n    SetPatchesNThreads(patches, n_default_threads);\n  }\n\n  /// @brief Internal use only. used to save field splines.\n  /// @param patches\n  /// @param n_default_threads\n  /// @param para_dim_if_none\n  /// @param dim_if_none\n  PyMultipatch(py::list& patches,\n               const int n_default_threads,\n               const int para_dim_if_none,\n               const int dim_if_none)\n      : n_default_threads_(n_default_threads),\n        has_null_splines_(true) {\n    SetPatchesWithNullSplines(patches,\n                              n_default_threads,\n                              para_dim_if_none,\n                              dim_if_none);\n  }\n\n  /// @brief given other shared pointer,  will copy references\n  /// ctor. Expected use is for  to_derived call.\n  ///\n  /// @param other\n  PyMultipatch(std::shared_ptr<PyMultipatch>& other) {\n    patches_ = other->patches_;\n    core_patches_ = other->core_patches_;\n    sub_multipatch_ = other->sub_multipatch_;\n    sub_patch_centers_ = other->sub_patch_centers_;\n    py_sub_multipatch_ = other->py_sub_multipatch_;\n    boundary_patch_ids_ = other->boundary_patch_ids_;\n    boundary_multipatch_ = other->boundary_multipatch_;\n    py_boundary_multipatch_ = other->py_boundary_multipatch_;\n    interfaces_ = other->interfaces_;\n    boundary_ids_ = other->boundary_ids_;\n    field_multipatches_ = other->field_multipatches_;\n    n_default_threads_ = other->n_default_threads_;\n    same_parametric_bounds_ = other->same_parametric_bounds_;\n    has_null_splines_ = other->has_null_splines_;\n    tolerance_ = other->tolerance_;\n  }\n\n  /// @brief Gets core patches\n  CorePatches_& CorePatches();\n\n  /// @brief Clears\n  void Clear();\n\n  /// @brief returns para_dim of the first patch\n  /// @return\n  int ParaDim() { return CorePatches()[0]->SplinepyParaDim(); }\n\n  /// @brief returns dim of the first patch\n  /// @return\n  int Dim() { return CorePatches()[0]->SplinepyDim(); }\n\n  /// @brief my name is Multipatch\n  /// @return\n  std::string Name() { return "Multipatch"; }\n\n  /// @brief Multipatch with n patches\n  /// @return\n  std::string WhatAmI() {\n    return "Multipatch with " + std::to_string(core_patches_.size())\n           + " patches.";\n  }\n\n  /// could overload, but it won\'t be clear for pybind\n  /// @brief default patches setter, exposed to python\n  /// @param patches\n  void SetPatchesDefault(py::list& patches) {\n    SetPatchesNThreads(patches, n_default_threads_);\n  }\n\n  /// @brief patches setter with nthreads\n  /// @param patches\n  /// @param nthreads\n  void SetPatchesNThreads(py::list& patches, const int nthreads = 1);\n\n  /// @brief patches setter for field patches that may contain null splines.\n  /// @param patches\n  /// @param nthreads\n  /// @param para_dim_if_none\n  /// @param dim_if_none\n  void SetPatchesWithNullSplines(py::list& patches,\n                                 const int nthreads,\n                                 const int para_dim_if_none,\n                                 const int dim_if_none);\n\n  /// @brief Gets patches\n  py::list GetPatches() { return patches_; }\n\n  /// @brief returns sub patches as multi patches, uses default nthreads\n  /// @return\n  std::shared_ptr<PyMultipatch> SubMultipatch();\n\n  /// @brief returns derived class of SubMultipatch\n  /// @return\n  py::object PySubMultipatch();\n\n  /// @brief Computes centers of subpatches\n  /// @return\n  py::array_t<double> SubPatchCenters();\n\n  /// @brief setter for interface info. runs array shape check\n  /// @param interfaces\n  void SetInterfaces(const py::array_t<int>& interfaces);\n\n  /// @brief getter for interface info. recomputes if unavailable\n  /// @param recompute compute even if already available\n  py::array_t<int> GetInterfaces(const bool recompute = false);\n\n  /// @brief Get the Boundary Orientations object\n  ///\n  /// @param tolerance\n  /// @param n_threads\n  /// @return py::tuple\n  py::array_t<int> GetInterfaceOrientations(const double tolerance,\n                                            const int n_threads);\n\n  /// @brief Gets IDs of boundary patch\n  /// @param bid boundary ID to be extracted\n  py::array_t<int> BoundaryPatchIds(const int bid);\n\n  /// @brief Gets boundary multi patch\n  /// @param bid boundary ID to be extracted\n  std::shared_ptr<PyMultipatch> BoundaryMultipatch(const int bid);\n\n  /// @brief returns derived class of boundary multi patch\n  /// @param bid boundary ID to be extracted\n  /// @return\n  py::object PyBoundaryMultipatch(const int bid);\n\n  /// @brief Evaluate at query points\n  /// @param queries Query points\n  /// @param nthreads Number of threads to use\n  py::array_t<double> Evaluate(py::array_t<double> queries, const int nthreads);\n\n  /// @brief Sample multi patch\n  /// @param resolution\n  /// @param nthreads Number of threads to use\n  /// @param same_parametric_bounds\n  py::array_t<double> Sample(const int resolution,\n                             const int nthreads,\n                             const bool same_parametric_bounds);\n\n  /// @brief Adds fields\n  /// @param fields\n  /// @param field_dim\n  /// @param check_name\n  /// @param check_dims\n  /// @param check_degrees\n  /// @param check_control_mesh_resolutions\n  /// @param nthreads\n  void AddFields(py::list& fields,\n                 const int field_dim,\n                 const bool check_name,\n                 const bool check_dims,\n                 const bool check_degrees,\n                 const bool check_control_mesh_resolutions,\n                 const int nthreads);\n\n  /// @brief Gets list of fields\n  py::list GetFields() { return field_multipatches_; }\n\n  /// @brief Get summed number of all control points\n  int GetNumberOfControlPoints();\n\n  /// @brief Get summed number of all control points\n  py::array_t<int> GetControlPointOffsets();\n\n  /// @brief Create a list of all control points\n  py::array_t<double> GetControlPoints();\n};\n\n/// @brief ToDerived for PyMultipatches\n/// @param core_obj\n/// @return\npy::object ToDerived(std::shared_ptr<PyMultipatch> core_obj);\n\n} // namespace splinepy::py\n',
            'splinepy/multipatch.py': '"""\nMultipatch Spline Configuration\n"""\n\nimport numpy as _np\n\nfrom splinepy import settings as _settings\nfrom splinepy._base import SplinepyBase as _SplinepyBase\nfrom splinepy.helpme import visualize as _visualize\nfrom splinepy.helpme.extract import Extractor as _Extractor\nfrom splinepy.spline import _default_if_none, _get_helper\nfrom splinepy.splinepy_core import PyMultipatch as _PyMultipatch\nfrom splinepy.splinepy_core import (\n    boundaries_from_continuity as _boundaries_from_continuity,\n)\nfrom splinepy.utils.data import MultipatchData as _MultipatchData\n\n\nclass Multipatch(_SplinepyBase, _PyMultipatch):\n    """\n    System of patches to store information such as boundaries and\n    interfaces\n    """\n\n    __slots__ = (\n        "_extractor",\n        "_show_options",\n        "_spline_data",\n    )\n\n    __show_option__ = _visualize.SplineShowOption\n\n    def __init__(self, splines=None, interfaces=None, *, spline=None):\n        """\n        Multipatch\n\n        Parameters\n        ----------\n        splines : list-like\n          List of splines to store as multipatch\n        interfaces : array-like\n          Defines the connectivity in between patches\n        spline : PyMultipatch\n          keyword only argument, implemented to support to_derived() interface.\n          calls move constructor.\n\n        Returns\n        -------\n        None\n        """\n        # Init values\n        if spline is not None:\n            if not isinstance(spline, _PyMultipatch):\n                raise TypeError("spline must be PyMultipatch.")\n            super().__init__(spline)\n        elif splines is not None:\n            super().__init__(splines, _settings.NTHREADS, False)\n        else:\n            super().__init__()\n\n        self._logd("Initialized Multipatch object")\n\n        if interfaces is not None:\n            self.interfaces = interfaces\n\n    @property\n    def patches(self):\n        """\n        List of splines in splinepy format\n\n        Returns\n        -------\n        patches : list\n         list of splines that are stored in the multipatch system\n\n\n        """\n        return super().patches\n\n    @patches.setter\n    def patches(self, list_of_splines):\n        _PyMultipatch.patches.fset(self, list_of_splines)\n\n    @property\n    def interfaces(self):\n        """\n        Determine the interfaces of a given multipatch system\n\n        Returns its interfaces in the form as an array of size\n        n_patches x n_sides_per_patch\n\n        The interfaces are stored as indices. If the index is negative, the ID\n        is referring to a boundary (e.g. for boundary conditions). If the\n        number is positive, the ID refers to the global face-id, which is\n        composed of the element ID and the local face ID :\n        global_face = local_face + number_of_faces_per_element * element_id\n\n        Example:\n\n        .. code-block ::\n\n          O -- 3 -- O O -- 3 -- O\n          |         | |         |\n          0    0    1 0    1    1\n          |         | |         |\n          O -- 2 -- O O -- 2 -- O\n\n        would be stored as:\n\n        .. code-block ::\n\n          [\n            [-1, 4, -1, -1],\n            [1, -1, -1, -1]\n          ]\n\n        Returns\n        -------\n        interfaces : np.ndarray\n          inter-patch connectivitiy and boundaries\n        """\n        # empty list as input will compute interfaces based on input\n        return super().get_interfaces(False)\n\n    @interfaces.setter\n    def interfaces(self, con):\n        """super() checks validity of input"""\n        # Assignment\n        super().set_interfaces(con)\n\n    def interface_orientations(self, tolerance=None, nthreads=None):\n        """\n        Determine orientation between adjacent splines which is required, e.g.,\n        for gismo export and orientation check\n\n        Parameters\n        ----------\n        tolerance : double\n          normed distance between two neighboring points to be considered equal\n        nthreads : int\n          Number of threads to be used for extraction, defaults to\n          settings.NTHREADS\n\n        Returns\n        -------\n        interface_orientations : np.array (np.int64)\n          description of the orientations between adjacent splines in a\n          multipatch object\n        """\n        return super().interface_orientations(\n            tolerance=_default_if_none(tolerance, _settings.TOLERANCE),\n            nthreads=_default_if_none(nthreads, _settings.NTHREADS),\n        )\n\n    @property\n    def boundaries(self):\n        """\n        Boundaries are stored within the interfaces array as negative entries\n\n        Negative entries mean, that there is a boundary, the absolute value\n        holds the boundary ID\n\n        Returns\n        -------\n        boundaries : list<np.ndarray>\n          list of 2D arrays, representing the patch and face ID\n        """\n        # Get minimum boundary id - boundary ids are stored as negative values\n        max_BID = self.interfaces.min()\n\n        boundary_list = []\n        for i_bid in range(-1, max_BID - 1, -1):\n            self._logd(f"Extracting boundary with ID {abs(i_bid)}")\n            boundary_list.append(_np.where(self.interfaces == i_bid))\n            self._logd(\n                f"Found {boundary_list[-1][1].size} boundary "\n                f"elements on boundary {abs(i_bid)}"\n            )\n\n        return boundary_list\n\n    def boundary_multipatch(self, bid=-1, nthreads=None):\n        """Extract all boundary patches of a given Multipatch system as splines\n\n        Parameters\n        ----------\n        bid : int\n          boundary id to extract, (default all if bid<0)\n        nthreads : int\n          Number of threads to be used for extraction, defaults to\n          settings.NTHREADS\n\n        Returns\n        -------\n        boundary_multipatch : Multipatch\n          Embedded splines representing boundaries of system\n        """\n        if nthreads is None:\n            nthreads = _settings.NTHREADS\n\n        # apply nthreads\n        previous_nthreads = self.n_default_threads\n        self.n_default_threads = nthreads\n\n        b_patches = super().boundary_multipatch(bid)\n\n        self.n_default_threads = previous_nthreads\n\n        return b_patches\n\n    def set_boundary(\n        self,\n        spline_ids,\n        boundary_faces,\n        boundary_id=None,\n    ):\n        """\n        Adds a boundary to a specific set of spline and spline-\n\n        Parameters\n        ----------\n        spline_ids : np.ndarray\n          array of spline-ids that are assigned a boundary\n        boundary_faces : np.ndarray\n          array of corresponding faces to be assigned a boundary\n        boundary_id : int\n          boundary_id to be assigned. If not chosen set to new lowest value\n\n        Returns\n        -------\n        None\n        """\n        # Get minimum boundary id - boundary ids are stored as negative values\n        max_BID = self.interfaces.min()\n\n        if boundary_id is None:\n            new_BID = max_BID - 1\n            self._logd(f"Creating new boundary with ID {abs(new_BID)}")\n        else:\n            # Make sure its negative\n            new_BID = -abs(int(boundary_id))\n            if new_BID < max_BID:\n                self._logd(f"Creating new boundary with ID {abs(new_BID)}")\n            else:\n                self._logd(\n                    "Adding new boundary elements to existing "\n                    f"boundary new boundary with ID {abs(new_BID)}"\n                )\n\n        try:\n            old_indices = self.interfaces[spline_ids, boundary_faces]\n\n        except BaseException:\n            raise ValueError(\n                "spline_ids and boundary_faces need to be one-dimensional, "\n                "array-like objects to access 2D interface numpy array"\n            )\n\n        # raise if any old indices include non-negative entries\n        # as it indicates that it\'s not a boundary sub-patch\n        if (old_indices > -1).any():\n            raise ValueError(\n                "One or more of the assigned boundary elements are not"\n                " on the patch surface, please check topology"\n            )\n\n        # set boundary id\n        self.interfaces[spline_ids, boundary_faces] = new_BID\n\n    @property\n    def para_dim(self):\n        """\n        Parametric dimension of the splineset\n\n        Returns\n        -------\n        para_dim : int\n          Parametric dimensionality of the multipatch system\n        """\n        return super().para_dim\n\n    @property\n    def dim(self):\n        """\n        Physical dimension of the splineset\n        Returns\n        -------\n        dim : int\n          Physical dimensionality of the multipatch system\n        """\n        return super().dim\n\n    @property\n    def sub_patch_centers(self):\n        """\n        Evaluated centers of the individual patches, used to determine\n        connectivity and identify boundaries based on position\n\n        Returns\n        -------\n        spline_centers : np.ndarray\n          coordinates of the patch-boundary centers\n        """\n        return super().sub_patch_centers()\n\n    def determine_interfaces(self, tolerance=None, recompute=False):\n        """\n        Retrieve interfaces info\n\n        Stores new information as interfaces\n\n        Parameters\n        ----------\n        tolerance : double\n          normed distance between two neighboring points to be considered equal\n        recompute : bool (False)\n          Enforce recomputation of interfaces\n\n        Returns\n        -------\n        interfaces : array-like (n_patch x n_boundaries)\n        """\n        if tolerance is None:\n            tolerance = _settings.TOLERANCE\n\n        # save previous default tol\n        previous_tol = self.tolerance\n\n        # set given tolerance and compute interfaces\n        self.tolerance = tolerance\n\n        # Enforces computation only if recompute or non-available\n        interfaces = super().get_interfaces(recompute)\n\n        self._logd("Successfully provided new interfaces using uff algorithm")\n\n        # set default tol back\n        self.tolerance = previous_tol\n\n        return interfaces\n\n    def boundary_from_function(\n        self,\n        function,\n        mask=None,\n        boundary_id=None,\n    ):\n        """\n        Uses all faces, that were identified as boundaries in the\n        interfaces array and checks if they fit a boundary function\n\n        Parameters\n        ----------\n        function : Callable\n          Function called on every boundary center point to check if it is on\n          the boundary, returns bool-type\n        mask : array-like\n          If assigned, takes only boundaries with matching ids\n        boundary_id : int\n          boundary_id to be assigned. If not chosen set to new lowest value\n\n        Returns\n        -------\n        None\n        """\n        # Get minimum boundary id - boundary ids are stored as negative values\n        max_BID = self.interfaces.min()\n\n        if boundary_id is None:\n            new_BID = max_BID - 1\n            self._logd(f"Creating new boundary with ID {abs(new_BID)}")\n        else:\n            # Make sure its negative\n            new_BID = -abs(int(boundary_id))\n            if new_BID < max_BID:\n                self._logd(f"Creating new boundary with ID {abs(new_BID)}")\n            else:\n                self._logd(\n                    "Adding new boundary elements to existing "\n                    f"boundary new boundary with ID {abs(new_BID)}"\n                )\n\n        # retrieve all boundary elements\n        if mask is None:\n            boundary_ids = self.interfaces < 0\n        else:\n            boundary_ids = _np.isin(-self.interfaces, _np.abs(mask))\n\n        # Check if there is a boundary\n        if not boundary_ids.any():\n            self._logd(\n                "No boundary elements could be identified that match "\n                "requirements"\n            )\n            return None\n\n        # Check all face centers\n        relevant_boundary_centers = self.sub_patch_centers[\n            boundary_ids.flatten(), :\n        ]\n\n        # Cols and Rows\n        row_ids, col_ids = _np.where(boundary_ids)\n\n        # Function is applied to all face centers\n        try:\n            new_boundary_bools = function(relevant_boundary_centers)\n        except BaseException:\n            raise ValueError(\n                "Function is not applicable to array. Function layout must"\n                " f(array<n_face_points,dim>) -> bools<n_face_points>"\n            )\n\n        # Assign new boundary ID to interfaces array\n        self.interfaces[\n            row_ids[new_boundary_bools], col_ids[new_boundary_bools]\n        ] = new_BID\n\n    @property\n    def spline_data(self):\n        """\n        Spline data helper for splines. @todo (does not do anything at the\n        moment)\n\n        Parameters\n        ----------\n        None\n\n        Returns\n        -------\n        spline_data: MultipatchData\n        """\n        return _get_helper(self, "_spline_data", _MultipatchData)\n\n    @property\n    def show_options(self):\n        """\n        Show option manager for Multipatches.\n\n        Parameters\n        ----------\n        None\n\n        Returns\n        -------\n        show_options: SplineShowOption\n        """\n        return _get_helper(self, "_show_options", self.__show_option__)\n\n    def showable(self, **kwargs):\n        """Equivalent to\n\n        .. code-block:: python\n\n            splinepy.helpme.visualize.show(\n                spline, return_showable=True, **kwargs\n            )\n\n        Parameters\n        ----------\n        kwargs: kwargs\n          see splinepy.helpme.visualize.show\n\n        Returns\n        -------\n        spline_showable: dict\n        """\n        return _visualize.show(self, return_showable=True, **kwargs)\n\n    def show(self, **kwargs):\n        return _visualize.show(self, **kwargs)\n\n    def boundaries_from_continuity(\n        self,\n        nthreads=None,\n        tolerance=None,\n    ):\n        """\n        Starting from a seed position, the splines are propagated until they\n        reach a kink (no g1 continuity). This uses the spline boundary\n        information and determines the interface information.\n\n        Parameters\n        ----------\n        nthreads : int\n          Number of threads to be used to determine boundaries and aux values\n        tolerance : double\n          Tolerance between two normal vectors [cos(angle)] to be considered G1\n\n        Returns\n        -------\n        None\n        """\n        if tolerance is None:\n            tolerance = _settings.TOLERANCE\n        if nthreads is None:\n            nthreads = _settings.NTHREADS\n        b_patches = self.boundary_multipatch(nthreads=nthreads)\n\n        # Pass information to c++ backend\n        self._logd("Start propagation of information...")\n        n_new_boundaries = _boundaries_from_continuity(\n            b_patches.patches,\n            b_patches.interfaces,\n            self.interfaces,\n            tolerance,\n            nthreads,\n        )\n        self._logd(f"{n_new_boundaries} new boundaries were assigned")\n\n    def combine_boundaries(self, mask=None):\n        """\n        Combines all boundaries that match an id from the mask to a single\n        boundary\n\n        Parameters\n        ----------\n        mask : array-like\n          List of boundary ids to be reassigned a new combined ID\n\n        Returns\n        -------\n        None\n        """\n        # retrieve all boundary elements\n        boundary_ids = _np.isin(-self.interfaces, _np.abs(mask))\n\n        if not boundary_ids.any():\n            self._logd(\n                "No boundary elements could be identified that match "\n                "requirements"\n            )\n            return None\n\n        self.interfaces[boundary_ids] = _np.min(mask)\n\n    def add_fields(\n        self,\n        fields,\n        field_dim,\n        check_compliance=True,\n        check_conformity=True,\n        nthreads=None,\n    ):\n        """\n        Add fields using lists of splines\n\n        Parameters\n        ----------\n        fields : list\n          Any number of list of splines to represent n-dimensional field with\n          equal parametric dimensionality\n        field_dim: int\n          Dimensionality of the individual fields\n        check_compliance : bool (True)\n          Check if field list is admissible, by comparing the parametric\n          dimensionality of the field entries with the spline list, and compare\n          patch sizes\n        check_conformity : bool (True)\n          Check for conformity between patches and fields by comparing degrees\n          and control-mesh-resolutions\n        nthreads : int\n\n        Returns\n        -------\n        None\n        """\n        if nthreads is None:\n            nthreads = _settings.NTHREADS\n\n        super().add_fields(\n            fields,\n            field_dim,\n            check_compliance,\n            check_compliance,\n            check_conformity,\n            check_conformity,\n            nthreads,\n        )\n\n    @property\n    def fields(self):\n        """Save fields as individual splines on patches\n\n        Parameters\n        ----------\n        None\n\n        Returns\n        -------\n        fields : list<Multipatch>\n          List of all field representation in the form of list of splines\n        """\n        return super().fields()\n\n    def sample(self, resolutions, nthreads=None):\n        """\n        Uniformly sample along each parametric dimensions from spline.\n\n        Parameters\n        -----------\n        resolutions: int\n        nthreads: int\n\n        Returns\n        --------\n        results: (math.product(resolutions), dim) np.ndarray\n        """\n\n        if not isinstance(resolutions, int) and hasattr(\n            resolutions, "__getitem__"\n        ):\n            self._logd(\n                "sample() only supports uniform sample. Taking first entry."\n            )\n            # for now, just take the first elem\n            resolutions = int(resolutions[0])\n\n        self._logd(\n            f"Sampling {resolutions ** self.para_dim} points from spline."\n        )\n        return super().sample(\n            resolutions,\n            nthreads=_default_if_none(nthreads, _settings.NTHREADS),\n            same_parametric_bounds=False,\n        )\n\n    def evaluate(self, queries, nthreads=None):\n        """\n        Evaluate each individual spline at specific parametric positions. To be\n        used with caution, as there is no check if the queries are within the\n        parametric bounds if settings.CHECK_BOUNDS is set to false.\n\n        Parameters\n        -----------\n        queries: (n, para_dim) array-like\n        nthreads: int\n\n        Returns\n        --------\n        results: (math.product(resolutions), dim) np.ndarray\n        """\n\n        return super().evaluate(\n            queries,\n            nthreads=_default_if_none(nthreads, _settings.NTHREADS),\n        )\n\n    @property\n    def extract(self):\n        """Return Extractor object to provide extract functionality for\n        multiple splines\n\n        Parameters\n        -----------\n        None\n\n        Returns\n        --------\n        extractor: Extractor\n        """\n        return _get_helper(self, "_extractor", _Extractor)\n',
            'src/py/py_multipatch.cpp': '/*\nMIT License\n\nCopyright (c) 2021 Jaewook Lee\n\nPermission is hereby granted, free of charge, to any person obtaining a copy\nof this software and associated documentation files (the "Software"), to deal\nin the Software without restriction, including without limitation the rights\nto use, copy, modify, merge, publish, distribute, sublicense, and/or sell\ncopies of the Software, and to permit persons to whom the Software is\nfurnished to do so, subject to the following conditions:\n\nThe above copyright notice and this permission notice shall be included in all\ncopies or substantial portions of the Software.\n\nTHE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\nIMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\nFITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE\nAUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER\nLIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,\nOUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN THE\nSOFTWARE.\n*/\n\n#include "splinepy/py/py_multipatch.hpp"\n\n#include <cstdlib>\n#include <mutex>\n#include <stdexcept>\n#include <unordered_map>\n\n// splinepy\n#include "splinepy/splines/helpers/scalar_type_wrapper.hpp"\n#include "splinepy/splines/null_spline.hpp"\n#include "splinepy/utils/grid_points.hpp"\n#include "splinepy/utils/nthreads.hpp"\n#include "splinepy/utils/print.hpp"\n\nnamespace splinepy::py {\n\nstd::vector<PySpline::CoreSpline_> ToCoreSplineVector(py::list pysplines,\n                                                      const int nthreads) {\n  // prepare return obj\n  const int n_splines = static_cast<int>(pysplines.size());\n  std::vector<PySpline::CoreSpline_> core_splines(n_splines);\n\n  auto to_core = [&](const int begin, const int end, int) {\n    for (int i{begin}; i < end; ++i) {\n      core_splines[i] =\n          pysplines[i].template cast<std::shared_ptr<PySpline>>()->Core();\n    }\n  };\n  splinepy::utils::NThreadExecution(to_core, n_splines, nthreads);\n\n  return core_splines;\n}\n\nstd::vector<PySpline::CoreSpline_>\nToCoreSplineVector(py::list pysplines,\n                   const int para_dim_if_none,\n                   const int dim_if_none,\n                   const int nthreads) {\n  // prepare return obj\n  const int n_splines = static_cast<int>(pysplines.size());\n  std::vector<PySpline::CoreSpline_> core_splines(n_splines);\n\n  auto to_core = [&](const int begin, const int end, int) {\n    for (int i{begin}; i < end; ++i) {\n      // get accessor\n      auto spline = pysplines[i];\n\n      // if None, fill null spline\n      if (spline.is_none()) {\n        core_splines[i] =\n            splinepy::splines::kNullSplineLookup[para_dim_if_none - 1]\n                                                [dim_if_none - 1];\n        continue;\n      }\n      core_splines[i] =\n          spline.template cast<std::shared_ptr<PySpline>>()->Core();\n    }\n  };\n  splinepy::utils::NThreadExecution(to_core, n_splines, nthreads);\n\n  return core_splines;\n}\n\npy::list ToPySplineList(CoreSplineVector& splist) {\n  // prepare return obj\n  const int n_splines = static_cast<int>(splist.size());\n\n  // to return\n  py::list pyspline_list(n_splines);\n\n  // cast - single threads, as we should respect GIL\n  for (int i{}; i < n_splines; ++i) {\n    pyspline_list[i] = std::make_shared<PySpline>(splist[i])->ToDerived();\n  }\n\n  return pyspline_list;\n}\n\ntemplate<typename T>\nIntVector ArgSort(const std::vector<T>& v) {\n  IntVector idx(v.size());\n  std::iota(idx.begin(), idx.end(), 0);\n  std::stable_sort(idx.begin(), idx.end(), [&v](int const& i1, int const& i2) {\n    return v[i1] < v[i2];\n  });\n  return idx;\n}\n\nvoid RaiseMismatch(const CoreSplineVector& splist,\n                   const std::string name,\n                   const int para_dim,\n                   const int dim,\n                   const IntVector& degrees,\n                   const IntVector& control_mesh_resolutions,\n                   const int nthreads) {\n  // for verbose output\n  std::unordered_map<std::string, IntVectorVector> mismatches{};\n\n  // check flags\n  bool check_name{}, check_para_dim{}, check_dim{}, check_degrees{},\n      check_control_mesh_resolutions{};\n  // input vector sizes\n  const int d_size = degrees.size();\n  const int cmr_size = control_mesh_resolutions.size();\n  // true para_dim to use as reference -> will be updated / compared\n  int ref_para_dim{para_dim};\n\n  // parse input and allocate vector for mismatch book keeping\n  if (name.size() > 0) {\n    check_name = true;\n    mismatches["name"].resize(nthreads);\n  }\n  if (dim > 0) {\n    check_dim = true;\n    mismatches["dim"].resize(nthreads);\n  }\n  if (d_size > 0) {\n    check_degrees = true;\n    ref_para_dim = d_size;\n    mismatches["degrees"].resize(nthreads);\n  }\n  if (cmr_size > 0) {\n    check_control_mesh_resolutions = true;\n    mismatches["control_mesh_resolutions"].resize(nthreads);\n  }\n  if (para_dim > 0 || check_degrees || check_control_mesh_resolutions) {\n    check_para_dim = true;\n\n    // sanity check\n    for (const auto& candidate : {para_dim, d_size, cmr_size}) {\n      if (candidate != ref_para_dim && candidate > 0) {\n        splinepy::utils::PrintAndThrowError(\n            "Mismatch in given para_dim (",\n            para_dim,\n            "), size of degrees, (",\n            d_size,\n            "), size of control_mesh_resolutions (",\n            cmr_size,\n            ").");\n      }\n    }\n    mismatches["para_dim"].resize(nthreads);\n  }\n\n  // lambda for nthread comparison\n  auto check_mismatch_step = [&](int, int, const int i_thread) {\n    // alloc vectors in case we need to compare\n    IntVector spline_degree(ref_para_dim), spline_cmr(ref_para_dim);\n    int total_ = static_cast<int>(splist.size());\n    for (int i{i_thread}; i < total_; i += nthreads) {\n      // get spline to check\n      const auto& spline = splist[i];\n\n      // skip null splines\n      if (spline->SplinepyIsNull()) {\n        continue;\n      }\n\n      // default value for para_dim match\n      bool para_dim_matches{true};\n\n      // check\n      if (check_name && (name != spline->SplinepySplineName())) {\n        mismatches["name"][i_thread].push_back(i);\n      }\n      if (check_para_dim && (ref_para_dim != spline->SplinepyParaDim())) {\n        mismatches["para_dim"][i_thread].push_back(i);\n        para_dim_matches = false;\n      }\n      if (check_dim && (dim != spline->SplinepyDim())) {\n        mismatches["dim"][i_thread].push_back(i);\n      }\n      // check properties that are relevant iff para_dim matches\n      if (para_dim_matches) {\n        if (check_degrees) {\n          spline->SplinepyCurrentProperties(spline_degree.data(),\n                                            nullptr,\n                                            nullptr,\n                                            nullptr);\n          if (spline_degree != degrees) {\n            mismatches["degrees"][i_thread].push_back(i);\n          }\n        }\n        if (check_control_mesh_resolutions) {\n          spline->SplinepyControlMeshResolutions(spline_cmr.data());\n          if (spline_cmr != control_mesh_resolutions) {\n            mismatches["control_mesh_resolutions"][i_thread].push_back(i);\n          }\n        }\n      }\n    }\n  };\n\n  splinepy::utils::NThreadExecution(check_mismatch_step,\n                                    static_cast<int>(splist.size()),\n                                    nthreads);\n\n  // prepare output or maybe exit\n  std::unordered_map<std::string, IntVector> concat_mismatches{};\n  bool raise{false};\n\n  for (const auto& [key, mismatch_per_threads] : mismatches) {\n    auto& concat_vec = concat_mismatches[key];\n    for (const auto& mismatch : mismatch_per_threads) {\n      const auto m_size = mismatch.size();\n      if (m_size != 0) {\n        concat_vec.insert(concat_vec.end(), mismatch.begin(), mismatch.end());\n      }\n    }\n    if (concat_vec.size() != 0) {\n      raise = true;\n    }\n  };\n\n  // everything matches\n  if (!raise) {\n    return;\n  }\n\n  // form mismatch info\n  std::string mismatch_info{};\n  for (const auto& [key, concat_mismatch] : concat_mismatches) {\n    mismatch_info += "\\n[" + key + "] : ";\n    for (const auto& ids : concat_mismatch) {\n      mismatch_info += std::to_string(ids) + ", ";\n    }\n  }\n\n  splinepy::utils::PrintAndThrowError("Found mismatches.", mismatch_info);\n}\n\nvoid RaiseMismatch(const CoreSplineVector& splist0,\n                   const CoreSplineVector& splist1,\n                   const bool name,\n                   const bool dimensionality,\n                   const int field_dim,\n                   const bool degrees,\n                   const bool control_mesh_resolutions,\n                   const int nthreads) {\n  // len check\n  if (splist0.size() != splist1.size()) {\n    splinepy::utils::PrintAndThrowError(\n        "Size mismatch between first and second list of splines.",\n        splist0.size(),\n        "vs",\n        splist1.size());\n  }\n  // for verbose output\n  std::unordered_map<std::string, IntVectorVector> mismatches{};\n  // parse input and allocate vector for mismatch book keeping\n  if (name) {\n    mismatches["name"].resize(nthreads);\n  }\n  if (dimensionality) {\n    mismatches["dim"].resize(nthreads);\n  }\n  if (degrees) {\n    mismatches["degrees"].resize(nthreads);\n  }\n  if (control_mesh_resolutions) {\n    mismatches["control_mesh_resolutions"].resize(nthreads);\n  }\n  if (dimensionality || degrees || control_mesh_resolutions) {\n    mismatches["para_dim"].resize(nthreads);\n  }\n\n  // lambda for nthread comparison\n  auto check_mismatch_step = [&](int, int, const int i_thread) {\n    // alloc some tmp vector if needed\n    IntVector int_vec0, int_vec1;\n    const int total_ = static_cast<int>(splist0.size());\n\n    for (int i{i_thread}; i < total_; i += nthreads) {\n      // get spline to check\n      const auto& spline0 = splist0[i];\n      const auto& spline1 = splist1[i];\n\n      // default value for para_dim match\n      bool para_dim_matches{true};\n\n      // check dims\n      if (dimensionality\n          && (spline0->SplinepyParaDim() != spline1->SplinepyParaDim())) {\n        mismatches["para_dim"][i_thread].push_back(i);\n        para_dim_matches = false;\n      }\n      if (dimensionality && (field_dim != spline1->SplinepyDim())) {\n        mismatches["dim"][i_thread].push_back(i);\n      }\n      // null spline should have at least same dims. but nothing else matters.\n      // skip null splines\n      if (spline1->SplinepyIsNull() || spline0->SplinepyIsNull()) {\n        continue;\n      }\n\n      if (name\n          && (spline0->SplinepySplineName() != spline1->SplinepySplineName())) {\n        mismatches["name"][i_thread].push_back(i);\n      }\n\n      // check properties that are relevant iff para_dim matches\n      if (para_dim_matches && (degrees || control_mesh_resolutions)) {\n        // alloc some space\n        int_vec0.resize(spline0->SplinepyParaDim());\n        int_vec1.resize(spline1->SplinepyParaDim());\n\n        if (degrees) {\n          spline0->SplinepyCurrentProperties(int_vec0.data(),\n                                             nullptr,\n                                             nullptr,\n                                             nullptr);\n          spline1->SplinepyCurrentProperties(int_vec1.data(),\n                                             nullptr,\n                                             nullptr,\n                                             nullptr);\n\n          if (int_vec0 != int_vec1) {\n            mismatches["degrees"][i_thread].push_back(i);\n          }\n        }\n\n        if (control_mesh_resolutions) {\n          spline0->SplinepyControlMeshResolutions(int_vec0.data());\n          spline1->SplinepyControlMeshResolutions(int_vec1.data());\n\n          if (int_vec0 != int_vec1) {\n            mismatches["control_mesh_resolutions"][i_thread].push_back(i);\n          }\n        }\n      }\n    }\n  };\n\n  splinepy::utils::NThreadExecution(check_mismatch_step,\n                                    static_cast<int>(splist0.size()),\n                                    nthreads);\n\n  // prepare output or maybe exit\n  std::unordered_map<std::string, IntVector> concat_mismatches{};\n  bool raise{false};\n\n  for (const auto& [key, mismatch_per_threads] : mismatches) {\n    auto& concat_vec = concat_mismatches[key];\n    for (const auto& mismatch : mismatch_per_threads) {\n      const auto m_size = mismatch.size();\n      if (m_size != 0) {\n        concat_vec.insert(concat_vec.end(), mismatch.begin(), mismatch.end());\n      }\n    }\n    if (concat_vec.size() != 0) {\n      raise = true;\n    }\n  };\n\n  // everything matches\n  if (!raise) {\n    return;\n  }\n\n  // form mismatch info\n  std::string mismatch_info{};\n  for (const auto& [key, concat_mismatch] : concat_mismatches) {\n    mismatch_info += "\\n[" + key + "] : ";\n    for (const auto& ids : concat_mismatch) {\n      mismatch_info += std::to_string(ids) + ", ";\n    }\n  }\n\n  splinepy::utils::PrintAndThrowError("Found mismatches.", mismatch_info);\n}\n\npy::array_t<int>\nFindConnectivityFromCenters(const py::array_t<double>& face_center_vertices,\n                            const int parametric_dimension,\n                            const py::array_t<double>& metric,\n                            const double tolerance) {\n\n  // -- Auxiliary data --\n  const int number_of_element_faces = parametric_dimension * 2;\n  const int number_of_patches =\n      face_center_vertices.shape(0) / number_of_element_faces;\n  const int physical_dimension = face_center_vertices.shape(1);\n  const int number_of_center_vertices{\n      static_cast<int>(face_center_vertices.shape(0))};\n  const double tolerance_squared{tolerance * tolerance};\n  const double* metric_ptr = static_cast<double*>(metric.request().ptr);\n  const double* face_center_vertices_ptr =\n      static_cast<double*>(face_center_vertices.request().ptr);\n\n  // Consistency check\n  if (!(face_center_vertices.shape(0) % number_of_element_faces == 0)) {\n    splinepy::utils::PrintAndThrowError(\n        "Number of corner vertices invalid. Must be a multiple of the number "\n        "of vertices per patch");\n  }\n  if (!(metric.size() == face_center_vertices.shape(1))) {\n    splinepy::utils::PrintAndThrowError(\n        "Incompatible size for metric. Must match physical dimension of face "\n        "center vertices");\n  }\n  if (!(number_of_center_vertices % number_of_element_faces == 0)) {\n    splinepy::utils::PrintAndThrowError(\n        "Inconsistent number of Center vertices. Must be divisible by "\n        "parametric_dimension*2");\n  }\n\n  // Init return type\n  py::array_t<int> connectivity(number_of_patches * number_of_element_faces);\n  int* connectivity_ptr = static_cast<int*>(connectivity.request().ptr);\n  // Init connectivity and metric value\n  // (-1 : boundary, -2 : untouched)\n  std::fill(connectivity_ptr,\n            connectivity_ptr + number_of_patches * number_of_element_faces,\n            -2);\n\n  // Assure Metric is normed and non-zero\n  const std::vector<double>& normed_metric = [&metric_ptr,\n                                              &physical_dimension]() {\n    double euclidian_norm = 0.;\n    for (int i_phys{}; i_phys < physical_dimension; i_phys++) {\n      euclidian_norm += metric_ptr[i_phys] * metric_ptr[i_phys];\n    }\n    std::vector<double> metric(physical_dimension, 1.);\n    euclidian_norm = std::sqrt(euclidian_norm);\n    if (euclidian_norm < 1e-20) {\n      return metric;\n    } else {\n      const double inv_euclidian_norm = 1 / euclidian_norm;\n      for (int i_phys{}; i_phys < physical_dimension; i_phys++) {\n        metric[i_phys] = metric_ptr[i_phys] * inv_euclidian_norm;\n      }\n    }\n    return metric;\n  }();\n\n  // Auxiliary function to determine distance between two points in face_center\n  auto squared_euclidian_distance =\n      [&face_center_vertices_ptr,\n       &physical_dimension](const int& i_start, const int& i_end) -> double {\n    double squared_euclidian_distance_{};\n    for (int i_phys{}; i_phys < physical_dimension; i_phys++) {\n      const double distance_c =\n          face_center_vertices_ptr[i_end * physical_dimension + i_phys]\n          - face_center_vertices_ptr[i_start * physical_dimension + i_phys];\n      squared_euclidian_distance_ += distance_c * distance_c;\n    }\n    return squared_euclidian_distance_;\n  };\n\n  std::vector<double> scalar_metric{};\n  scalar_metric.reserve(number_of_center_vertices);\n\n  // Check Metric Dimension and Vector Size\n  for (int i_vertex{}; i_vertex < number_of_center_vertices; i_vertex++) {\n    double metric_v = normed_metric[0]\n                      * face_center_vertices_ptr[i_vertex * physical_dimension];\n    for (int j_phys{1}; j_phys < physical_dimension; j_phys++) {\n      metric_v =\n          normed_metric[j_phys]\n          * face_center_vertices_ptr[i_vertex * physical_dimension + j_phys];\n    }\n    scalar_metric.push_back(metric_v);\n  }\n\n  // Sort Metric Vector\n  const auto metric_order_indices = ArgSort(scalar_metric);\n\n  // Loop over points\n  for (int lower_limit = 0; lower_limit < number_of_center_vertices - 1;\n       lower_limit++) {\n    // Loop over all points regardless of whether they have been touched or not,\n    // and then check the validity of the connection Point already processed\n    bool found_duplicate = false;\n    // Now check allowed range for duplicates\n    int upper_limit = lower_limit + 1;\n    while (upper_limit < number_of_center_vertices\n           && (scalar_metric[metric_order_indices[upper_limit]]\n               - scalar_metric[metric_order_indices[lower_limit]])\n                  < tolerance) {\n      // Check if the two points are duplicates\n      found_duplicate =\n          squared_euclidian_distance(metric_order_indices[lower_limit],\n                                     metric_order_indices[upper_limit])\n          < tolerance_squared;\n      if (found_duplicate) {\n        break;\n      } else {\n        upper_limit++;\n      }\n    }\n\n    // Now we have to check if the connection is valid\n    // 1. If another connection is found, that means, that the point it connects\n    //    to has a higher index in the metric tensor. If the current point does\n    //    already have a neighbor, that means that more than one point connect\n    //    -> Error\n    if (found_duplicate) {\n      if (connectivity_ptr[metric_order_indices[lower_limit]] != -2) {\n        splinepy::utils::PrintAndThrowError(\n            "Found conflicting interceptions, where more than two points are "\n            "in the same position. Expected -2 got",\n            connectivity_ptr[metric_order_indices[lower_limit]]);\n      }\n\n      // If both tests passed, update connectivity\n      connectivity_ptr[metric_order_indices[lower_limit]] =\n          static_cast<int>(metric_order_indices[upper_limit]);\n      connectivity_ptr[metric_order_indices[upper_limit]] =\n          static_cast<int>(metric_order_indices[lower_limit]);\n    } else {\n      // set Boundary-ID\n      if (connectivity_ptr[metric_order_indices[lower_limit]] == -2) {\n        connectivity_ptr[metric_order_indices[lower_limit]] = -1;\n      }\n    }\n  }\n\n  // Treat last remaining point in scalar metric vector\n  if (connectivity_ptr[metric_order_indices[number_of_center_vertices - 1]]\n      == -2) {\n    connectivity_ptr[metric_order_indices[number_of_center_vertices - 1]] = -1;\n  }\n\n  // Resize buffer\n  connectivity.resize({number_of_patches, number_of_element_faces});\n  return connectivity;\n}\n\npy::array_t<int>\nInterfacesFromBoundaryCenters(const py::array_t<double>& py_center_vertices,\n                              const double& tolerance,\n                              const int& parametric_dimension) {\n  // Determine Metric\n  const int physical_dimension = py_center_vertices.shape(1);\n  const int number_of_corner_points = py_center_vertices.shape(0);\n  py::array_t<double> maxvertex(physical_dimension),\n      minvertex{physical_dimension};\n\n  // Get pointers\n  double* maxvertex_ptr = static_cast<double*>(maxvertex.request().ptr);\n  double* minvertex_ptr = static_cast<double*>(minvertex.request().ptr);\n  const double* py_center_vertices_ptr =\n      static_cast<double*>(py_center_vertices.request().ptr);\n\n  // Calculate limits of center vertices\n  for (int i_dim{}; i_dim < physical_dimension; i_dim++) {\n    minvertex_ptr[i_dim] = py_center_vertices_ptr[i_dim];\n    maxvertex_ptr[i_dim] = py_center_vertices_ptr[i_dim];\n  }\n  for (int i_c{1}; i_c < number_of_corner_points; i_c++) {\n    for (int i_dim{}; i_dim < physical_dimension; i_dim++) {\n      maxvertex_ptr[i_dim] =\n          std::max(py_center_vertices_ptr[i_c * physical_dimension + i_dim],\n                   maxvertex_ptr[i_dim]);\n      minvertex_ptr[i_dim] =\n          std::min(py_center_vertices_ptr[i_c * physical_dimension + i_dim],\n                   minvertex_ptr[i_dim]);\n    }\n  }\n\n  // Determine Interfaces\n  return FindConnectivityFromCenters(py_center_vertices,\n                                     parametric_dimension,\n                                     maxvertex - minvertex,\n                                     tolerance);\n}\n\nvoid GetInterfaceOrientation(\n    const std::shared_ptr<splinepy::splines::SplinepyBase>& pyspline_start,\n    const int& boundary_start,\n    const std::shared_ptr<splinepy::splines::SplinepyBase>& pyspline_end,\n    const int& boundary_end,\n    const double& tolerance,\n    int* mappings_ptr,\n    int* orientations_ptr) {\n  // Init return values and get auxiliary data\n  const int& para_dim_ = pyspline_start->SplinepyParaDim();\n  const int& dim_ = pyspline_start->SplinepyDim();\n\n  // Checks\n  if ((para_dim_ != pyspline_end->SplinepyParaDim())\n      || (dim_ != pyspline_end->SplinepyDim())) {\n    splinepy::utils::PrintAndThrowError(\n        "Spline Orientation can not be checked, as they have mismatching"\n        "dimensionality start spline has dimensions ",\n        para_dim_,\n        "D -> ",\n        dim_,\n        "D, the adjacent one has dimensions ",\n        pyspline_end->SplinepyParaDim(),\n        "D -> ",\n        pyspline_end->SplinepyDim(),\n        "D.");\n  }\n\n  // First Check the orientation of the first entry by comparing their ids\n  const int boundary_start_p_dim = static_cast<int>(boundary_start / 2);\n  const bool boundary_start_orientation = (boundary_start % 2) == 0;\n  const int boundary_end_p_dim = static_cast<int>(boundary_end / 2);\n  const bool boundary_end_orientation = (boundary_end % 2) == 0;\n  mappings_ptr[boundary_start_p_dim] = boundary_end_p_dim;\n  // Note: Here might be a discrepancy with gismo\'s orientation, and it needs to\n  // be checked in the future. I am awaiting a response from gismo developers,\n  // it is poosible the orientation of the interface edge might be flipped\n  // (bugfix: negate the following expression)\n  orientations_ptr[boundary_start_p_dim] =\n      (boundary_start_orientation ^ boundary_end_orientation) ? 1 : 0;\n\n  /// Compare jacobians for remaining entries\n  // Calculate Parametric bounds\n  std::vector<double> bounds_start(para_dim_ * 2);\n  pyspline_start->SplinepyParametricBounds(bounds_start.data());\n  std::vector<double> bounds_end(para_dim_ * 2);\n  pyspline_end->SplinepyParametricBounds(bounds_end.data());\n  // Determine face center position in parametric space\n  std::vector<double> boundary_center_start(para_dim_),\n      boundary_center_end(para_dim_);\n\n  for (int i{}; i < para_dim_; i++) {\n    if (i == boundary_start_p_dim) {\n      boundary_center_start[i] = boundary_start_orientation\n                                     ? bounds_start[i]\n                                     : bounds_start[i + para_dim_];\n    } else {\n      boundary_center_start[i] =\n          .5 * (bounds_start[i] + bounds_start[i + para_dim_]);\n    }\n    if (i == boundary_end_p_dim) {\n      boundary_center_end[i] =\n          boundary_end_orientation ? bounds_end[i] : bounds_end[i + para_dim_];\n    } else {\n      boundary_center_end[i] = .5 * (bounds_end[i] + bounds_end[i + para_dim_]);\n    }\n  }\n\n  // Calculate Jacobians\n  std::vector<double> jacobian_start(para_dim_ * dim_),\n      jacobian_end(para_dim_ * dim_);\n  pyspline_start->SplinepyJacobian(boundary_center_start.data(),\n                                   jacobian_start.data());\n  pyspline_end->SplinepyJacobian(boundary_center_end.data(),\n                                 jacobian_end.data());\n\n  // Check the angle between the jacobian entries\n  for (int i_pd{}; i_pd < para_dim_; i_pd++) {\n    if (i_pd == boundary_start_p_dim) {\n      continue;\n    }\n    double norm_s{};\n    for (int k{}; k < dim_; k++) {\n      // [i_query * pdim * dim + i_paradim * dim + i_dim]\n      norm_s += jacobian_start[i_pd + k * para_dim_]\n                * jacobian_start[i_pd + k * para_dim_];\n    }\n    for (int j{}; j < para_dim_; j++) {\n      double norm_e{}, dot_p{};\n      for (int k{}; k < dim_; k++) {\n        dot_p += jacobian_start[i_pd + k * para_dim_]\n                 * jacobian_end[j + k * para_dim_];\n        norm_e +=\n            jacobian_end[j + k * para_dim_] * jacobian_end[j + k * para_dim_];\n      }\n\n      // Check angle\n      const double cos_angle = abs(dot_p / std::sqrt(norm_s * norm_e));\n      if (cos_angle > (1. - tolerance)) {\n        mappings_ptr[i_pd] = j;\n        orientations_ptr[i_pd] = (dot_p > 0) ? 1 : 0;\n        break;\n      }\n    }\n  }\n}\n\npy::array_t<int> PyMultipatch::GetInterfaceOrientations(const double tolerance,\n                                                        const int n_threads) {\n\n  // Check if already exists\n  if (interface_orientations_.size() != 0) {\n    return interface_orientations_;\n  }\n\n  int n_patches = patches_.size();\n\n  // get para dim of the first patch\n  int para_dim = ParaDim();\n\n  const int n_faces_per_element = 2 * para_dim;\n  // 4 includes - patch id start, face id start, patch id end, face id end\n  const int n_entries_per_line = 4 + 2 * para_dim;\n\n  // Make sure Interfaces are available\n  const int* interfaces_ptr =\n      static_cast<int*>(GetInterfaces(false).request().ptr);\n\n  // Loop over interfaces to compute number of interfaces (This is generally not\n  // time critical as comparisons are much more expensive)\n  int number_of_interfaces{};\n  for (int i_interface{}; i_interface < interfaces_.size(); i_interface++) {\n    if (interfaces_ptr[i_interface] >= 0) {\n      // interface found\n      if (interfaces_ptr[i_interface] > i_interface) {\n        number_of_interfaces++;\n      }\n    }\n  }\n\n  interface_orientations_ =\n      py::array_t<int>({number_of_interfaces, n_entries_per_line});\n  int* orientations_ptr =\n      static_cast<int*>(interface_orientations_.request().ptr);\n\n  // Second loop to fill the interface information\n  int i_connection{};\n  for (int i_interface{}; i_interface < interfaces_.size(); i_interface++) {\n    if (interfaces_ptr[i_interface] >= 0) {\n      // interface found\n      if (interfaces_ptr[i_interface] > i_interface) {\n        orientations_ptr[i_connection * n_entries_per_line + 0] =\n            i_interface / n_faces_per_element;\n        orientations_ptr[i_connection * n_entries_per_line + 1] =\n            i_interface % n_faces_per_element; // std::div\n        orientations_ptr[i_connection * n_entries_per_line + 2] =\n            interfaces_ptr[i_interface] / n_faces_per_element;\n        orientations_ptr[i_connection * n_entries_per_line + 3] =\n            interfaces_ptr[i_interface] % n_faces_per_element; // std::div\n        i_connection++;\n      }\n    }\n  }\n\n  // Sanity check\n  assert(i_connection == number_of_interfaces);\n\n  const auto cpp_spline_list = ToCoreSplineVector(patches_, n_threads);\n\n  // Provide lambda for multithread execution\n  auto get_orientation = [&](const int start, const int end, int) {\n    for (int i{start}; i < end; ++i) {\n      // Assign connections (start and end faces)\n      const int& patch_id_start = orientations_ptr[i * n_entries_per_line + 0];\n      const int& face_id_start = orientations_ptr[i * n_entries_per_line + 1];\n      const int& patch_id_end = orientations_ptr[i * n_entries_per_line + 2];\n      const int& face_id_end = orientations_ptr[i * n_entries_per_line + 3];\n\n      // Determine the mappings\n      GetInterfaceOrientation(\n          cpp_spline_list[patch_id_start],\n          face_id_start,\n          cpp_spline_list[patch_id_end],\n          face_id_end,\n          tolerance,\n          &orientations_ptr[i * n_entries_per_line + 4],\n          &orientations_ptr[i * n_entries_per_line + 4 + para_dim]);\n    }\n  };\n\n  // Execute in parallel\n  splinepy::utils::NThreadExecution(get_orientation,\n                                    number_of_interfaces,\n                                    n_threads);\n\n  // Resize and return\n\n  return interface_orientations_;\n}\n\npy::list ExtractAllBoundarySplines(const py::list& spline_list,\n                                   const py::array_t<int>& interfaces,\n                                   const int& n_threads) {\n  // Check input data\n  if (static_cast<int>(py::len(spline_list)) != interfaces.shape(0)) {\n    splinepy::utils::PrintAndThrowError(\n        "Number of splines in list (",\n        py::len(spline_list),\n        ") and number of elements in interfaces (",\n        interfaces.shape(0),\n        ") does not match.");\n  }\n\n  if (n_threads < 1) {\n    splinepy::utils::PrintAndThrowError(\n        "Number of threads must be positive integer.");\n  }\n  // Auxiliary data\n  py::list boundary_splines{};\n  std::vector<py::list> lists_to_concatenate(n_threads);\n  const int* interface_ptr = static_cast<int*>(interfaces.request().ptr);\n  const int n_patches = interfaces.shape(0);\n  const int n_faces = interfaces.shape(1);\n  const int para_dim_ = n_faces / 2;\n  const auto cpp_spline_list = ToCoreSplineVector(spline_list);\n  const int chunk_size = std::div((n_patches + n_threads - 1), n_threads).quot;\n\n  // This approach is a work-around for parallel execution\n  auto extract_boundaries = [&](const int start, const int end, int) {\n    // start : process-ID\n    // end : unused hence no referencing\n\n    auto& boundaries_local = lists_to_concatenate[start];\n    // Start extraction (remaining order)\n    for (int i{start}; i < end; i++) {\n      for (int j{}; j < n_faces; j++) {\n        if (interface_ptr[i * n_faces + j] < 0) {\n          boundaries_local.append(\n              // Extract Boundary splines\n              PySpline(cpp_spline_list[i]->SplinepyExtractBoundary(j)));\n        }\n      }\n    }\n  };\n\n  // Execute in parallel\n  splinepy::utils::NThreadExecution(extract_boundaries, n_threads, n_threads);\n\n  // Concatenate list of boundaries - should only copy pointers\n  for (auto& entries : lists_to_concatenate) {\n    boundary_splines += entries;\n  }\n\n  return boundary_splines;\n}\n\nint AddBoundariesFromContinuity(const py::list& boundary_splines,\n                                const py::array_t<int>& boundary_interfaces,\n                                py::array_t<int>& global_interfaces,\n                                const double& tolerance,\n                                const int& n_threads) {\n  // Check input data\n  if (static_cast<int>(py::len(boundary_splines))\n      != boundary_interfaces.shape(0)) {\n    splinepy::utils::PrintAndThrowError(\n        "Number of splines in list (",\n        py::len(boundary_splines),\n        ") and number of elements in connectivity (",\n        boundary_interfaces.shape(0),\n        ") does not match.");\n  }\n\n  // Provide auxiliary values\n  const auto cpp_spline_list = ToCoreSplineVector(boundary_splines);\n\n  const int n_boundary_patches{static_cast<int>(boundary_interfaces.shape(0))};\n  const int n_faces_per_boundary_patch{\n      static_cast<int>(boundary_interfaces.shape(1))};\n  const int para_dim_{n_faces_per_boundary_patch / 2};\n  const int dim_ = cpp_spline_list[0]->SplinepyDim();\n  const int* boundary_interfaces_ptr =\n      static_cast<int*>(boundary_interfaces.request().ptr);\n  int* global_interfaces_ptr =\n      static_cast<int*>(global_interfaces.request().ptr);\n\n  // This function is currently only implemented for 2D and 3D applications. For\n  // higher dimensions, please revise the implementation of the generalized\n  // cross product as can be found here:\n  // https://math.stackexchange.com/questions/752774/generalized-cross-product\n  if ((dim_ < 1) || (dim_ > 3)) {\n    splinepy::utils::PrintAndThrowError(\n        "G1-based boundary computation is only supported for 2D and 3D "\n        "multipatches. If this is a feature you require, please consider "\n        "writing an issue on our github");\n  }\n\n  // Auxiliary Lambdas to keep code clean\n  // Check if to normal vectors are g1 (tol > cos(phi))\n  auto areG1 = [&tolerance, &dim_](const std::vector<double>& vec0,\n                                   const std::vector<double>& vec1) -> bool {\n    // Checks in Debug\n    assert(static_cast<int>(vec0.size()) == dim_);\n    assert(static_cast<int>(vec1.size()) == dim_);\n\n    // Start actual computation\n    double norm0{}, norm1{}, dot_p{};\n    for (int i{}; i < dim_; i++) {\n      norm0 += vec0[i] * vec0[i];\n      norm1 += vec1[i] * vec1[i];\n      dot_p += vec0[i] * vec1[i];\n    }\n    return (tolerance > abs(1 - abs(dot_p) / std::sqrt(norm0 * norm1)));\n  };\n\n  // Tangential Vector on boundary based on its derivative\n  auto normal_vector = [&cpp_spline_list, &para_dim_, &dim_](\n                           const int& patch_id,\n                           const int& face_id) -> std::vector<double> {\n    // init return value (are default initialized to 0)\n    std::vector<double> para_coord(para_dim_), bounds(2 * para_dim_),\n        normal_vector(dim_), jacobian(dim_ * para_dim_);\n\n    // Auxiliary values\n    const int axis_dim = face_id / 2;\n    const int is_in_front = face_id % 2;\n\n    // Parametric Bounds\n    const auto& spline = cpp_spline_list[patch_id];\n    spline->SplinepyParametricBounds(bounds.data());\n\n    for (int i{}; i < para_dim_; i++) {\n      if (i == axis_dim) {\n        para_coord[i] = bounds[i + is_in_front * para_dim_];\n      } else {\n        para_coord[i] = .5 * (bounds[i + para_dim_] + bounds[i]);\n      }\n    }\n\n    // Compute Jacobian\n    spline->SplinepyJacobian(para_coord.data(), jacobian.data());\n\n    // Compute Cross-Product\n    if (dim_ == 2) {\n      normal_vector[0] = -jacobian[1];\n      normal_vector[1] = jacobian[0];\n    } else if (dim_ == 3) {\n      normal_vector[0] = jacobian[2] * jacobian[5] - jacobian[4] * jacobian[3];\n      normal_vector[1] = jacobian[4] * jacobian[1] - jacobian[0] * jacobian[5];\n      normal_vector[2] = jacobian[0] * jacobian[3] - jacobian[2] * jacobian[1];\n    } else {\n      // This should never happen!\n      splinepy::utils::PrintAndThrowError(\n          "G1-based boundary computation is only supported for 2D and 3D "\n          "multipatches. If this is a feature you require, please consider "\n          "writing an issue on our github");\n    }\n    return normal_vector;\n  };\n\n  // Start Computations ------------------------------------------------ //\n  // while the actual propagation needs to be performed in serial, the\n  // precomputation of interface tolerances can be performed in parallel\n  std::vector<bool> faces_are_g1(n_faces_per_boundary_patch\n                                 * n_boundary_patches);\n  auto precompute_tolerances = [&](const int start, const int end, int) {\n    // Loop over relevant faces\n    for (int i{start}; i < end; i++) {\n      // Loop over faces\n      for (int j{}; j < n_faces_per_boundary_patch; j++) {\n        // Interface refers to the global face id (see interface documentation)\n        const int& connected_face_id =\n            boundary_interfaces_ptr[i * n_faces_per_boundary_patch + j];\n\n        // Retrieve patch and face ID of neighbor\n        const int adjacent_element_id =\n            connected_face_id / n_faces_per_boundary_patch;\n        const int adjacent_face_id =\n            connected_face_id % n_faces_per_boundary_patch;\n\n        // only compute if the adjacent neighbor has higher id to prevent double\n        // the work\n        if (adjacent_element_id < i) {\n          continue;\n        }\n        // Get tangential vector of current patch\n        const std::vector<double> vec0 = normal_vector(i, j);\n\n        // Get corresponding tangential vector of neighbor patch\n        const std::vector<double> vec1 =\n            normal_vector(adjacent_element_id, adjacent_face_id);\n\n        // Check tolerance\n        const bool is_g1 = areG1(vec0, vec1);\n        faces_are_g1[i * n_faces_per_boundary_patch + j] = is_g1;\n        faces_are_g1[connected_face_id] = is_g1;\n      }\n    }\n  };\n\n  // Execute in parallel\n  splinepy::utils::NThreadExecution(precompute_tolerances,\n                                    n_boundary_patches,\n                                    n_threads);\n\n  // std::vector can use less memory for bools\n  std::vector<bool> is_assigned(n_boundary_patches); // defaults false\n  std::vector<int> new_boundary_id(n_boundary_patches);\n  std::vector<int> queued_splines{};\n\n  // Start Assignment\n  // Loop over all patches\n  int current_max_id{1};\n  for (int i{}; i < n_boundary_patches; i++) {\n    if (is_assigned[i]) {\n      continue;\n    }\n    new_boundary_id[i] = current_max_id;\n    is_assigned[i] = true;\n    queued_splines.push_back(i);\n\n    // Start propagation\n    while (!queued_splines.empty()) {\n      const int current_id = queued_splines.back();\n      queued_splines.pop_back();\n      for (int i_face{}; i_face < n_faces_per_boundary_patch; i_face++) {\n        const int combined_index =\n            current_id * n_faces_per_boundary_patch + i_face;\n        // Is the neighborface G1\n        if (faces_are_g1[combined_index]) {\n          // Adjacent global face id\n          const int& adjacent_global_face_id =\n              boundary_interfaces_ptr[combined_index];\n          const int adjacent_patch_id =\n              adjacent_global_face_id / n_faces_per_boundary_patch;\n\n          // Check if the adjacent patch is already assigned\n          if (is_assigned[adjacent_patch_id]) {\n            continue;\n          } else {\n            // Assign a BID and continue\n            new_boundary_id[adjacent_patch_id] = current_max_id;\n            is_assigned[adjacent_patch_id] = true;\n            queued_splines.push_back(adjacent_patch_id);\n          }\n        }\n      }\n    }\n\n    // End propagation and increase id\n    current_max_id++;\n  }\n\n  // Assign the new boundary ids to the old interface-vector\n  const int& n_interfaces = global_interfaces.size();\n  int counter{};\n  for (int i{}; i < n_interfaces; i++) {\n    if (global_interfaces_ptr[i] < 0) {\n      global_interfaces_ptr[i] = -new_boundary_id[counter];\n      counter++;\n    }\n  }\n  if (counter != n_boundary_patches) {\n    splinepy::utils::PrintAndThrowError(\n        counter,\n        " new boundary ids were assigned, however ",\n        n_boundary_patches,\n        " were expected, which means information was lost. Abort mission");\n  }\n\n  return current_max_id;\n}\n\ntypename PyMultipatch::CorePatches_& PyMultipatch::CorePatches() {\n  if (core_patches_.size() == 0) {\n    splinepy::utils::PrintAndThrowError("No splines/patches set");\n  }\n  return core_patches_;\n}\n\nvoid PyMultipatch::Clear() {\n  patches_ = py::list();\n  core_patches_ = CorePatches_{};\n  sub_multipatch_ = nullptr;\n  boundary_patch_ids_ = py::array_t<int>();\n  boundary_multipatch_ = nullptr;\n  interfaces_ = py::array_t<int>();\n  interface_orientations_ = py::array_t<int>();\n  boundary_ids_ = py::array_t<int>();\n  sub_patch_centers_ = py::array_t<double>();\n  field_multipatches_ = py::list();\n}\n\nvoid PyMultipatch::SetPatchesNThreads(py::list& patches, const int nthreads) {\n  // clear first, in case this is a new setting\n  Clear();\n\n  // register patches\n  patches_ = patches;\n\n  // convert\n  core_patches_ = ToCoreSplineVector(patches, nthreads);\n\n  // check only dim mismatch\n  RaiseMismatch(core_patches_,\n                "",\n                core_patches_[0]->SplinepyParaDim(),\n                core_patches_[0]->SplinepyDim(),\n                {},\n                {},\n                nthreads);\n}\n\nvoid PyMultipatch::SetPatchesWithNullSplines(py::list& patches,\n                                             const int nthreads,\n                                             const int para_dim_if_none,\n                                             const int dim_if_none) {\n  // clear\n  Clear();\n\n  // save\n  patches_ = patches;\n\n  // convert using null spline friendly converter\n  core_patches_ =\n      ToCoreSplineVector(patches, para_dim_if_none, dim_if_none, nthreads);\n\n  // check only dim mismatch\n  RaiseMismatch(core_patches_,\n                "",\n                core_patches_[0]->SplinepyParaDim(),\n                core_patches_[0]->SplinepyDim(),\n                {},\n                {},\n                nthreads);\n}\n\nstd::shared_ptr<PyMultipatch> PyMultipatch::SubMultipatch() {\n  // quick exit if they exist.\n  if (sub_multipatch_) {\n    return sub_multipatch_;\n  }\n\n  const int n_splines = CorePatches().size();\n  // to accumulate\n  const int n_boundary = ParaDim() * 2;\n  const int n_boundaries = n_splines * n_boundary;\n\n  // prepare output\n  CoreSplineVector out_boundaries(n_boundaries);\n\n  // prepare lambda\n  auto boundary_extract = [&](const int begin, const int end, int) {\n    for (int i{begin}; i < end; ++i) {\n      // start of the offset\n      const int offset = i * n_boundary;\n      // deref this spline\n      auto& spline = *core_patches_[i];\n      for (int j{}; j < n_boundary; ++j) {\n        out_boundaries[offset + j] = spline.SplinepyExtractBoundary(j);\n      }\n    }\n  };\n\n  splinepy::utils::NThreadExecution(boundary_extract,\n                                    n_splines,\n                                    n_default_threads_);\n\n  // create multi patch to return\n  sub_multipatch_ = std::make_shared<PyMultipatch>();\n\n  // set both core and py splines\n  sub_multipatch_->patches_ = ToPySplineList(out_boundaries);\n  sub_multipatch_->core_patches_ = std::move(out_boundaries);\n\n  return sub_multipatch_;\n}\n\npy::object PyMultipatch::PySubMultipatch() {\n  if (py_sub_multipatch_.is_none()) {\n    py_sub_multipatch_ = ToDerived(SubMultipatch());\n  }\n  return py_sub_multipatch_;\n}\n\npy::array_t<double> PyMultipatch::SubPatchCenters() {\n  // return saved\n  if (sub_patch_centers_.size() > 0) {\n    return sub_patch_centers_;\n  }\n\n  // prepare output\n  // from here we assume that all the splines have the same para_dim and dim\n  const int n_splines = CorePatches().size();\n  const int para_dim = ParaDim();\n  const int dim = Dim();\n  const int n_queries = 2 * para_dim;\n  const int n_total = n_queries * n_splines;\n  sub_patch_centers_ = py::array_t<double>({n_total, dim});\n  double* sub_patch_centers_ptr =\n      static_cast<double*>(sub_patch_centers_.request().ptr);\n\n  // pre-compute boundary centers\n  DoubleVector para_bounds;\n  double* para_bounds_ptr;\n  if (!same_parametric_bounds_) {\n    para_bounds.resize(n_total * para_dim);\n    para_bounds_ptr = para_bounds.data();\n    const int stride = n_queries * para_dim;\n\n    auto calc_para_bounds = [&](const int begin, const int end, int) {\n      for (int i{begin}; i < end; ++i) {\n        splinepy::splines::helpers::ScalarTypeBoundaryCenters(\n            *core_patches_[i],\n            &para_bounds_ptr[stride * i]);\n      }\n    };\n\n    // exe\n    splinepy::utils::NThreadExecution(calc_para_bounds,\n                                      n_splines,\n                                      n_default_threads_);\n  }\n\n  auto calc_sub_patch_centers_step = [&](int, int, const int i_thread) {\n    // each thread needs one query\n    DoubleVector queries_vector; /* unused if same_parametric_bounds=true*/\n    double* queries;\n\n    // pre compute boundary centers if para bounds are the same\n    if (same_parametric_bounds_) {\n      queries_vector.resize(2 * para_dim * para_dim);\n      queries = queries_vector.data();\n      splinepy::splines::helpers::ScalarTypeBoundaryCenters(*core_patches_[0],\n                                                            queries);\n    }\n\n    for (int i{i_thread}; i < n_total; i += n_default_threads_) {\n      const auto [i_spline, i_query] = std::div(i, n_queries);\n\n      // get ptr start\n      if (!same_parametric_bounds_) {\n        queries = &para_bounds_ptr[i_spline * n_queries * para_dim];\n      }\n\n      // eval\n      core_patches_[i_spline]->SplinepyEvaluate(\n          &queries[i_query * para_dim],\n          &sub_patch_centers_ptr[(i_spline * n_queries + i_query) * dim]);\n    }\n  };\n\n  splinepy::utils::NThreadExecution(calc_sub_patch_centers_step,\n                                    n_total,\n                                    n_default_threads_);\n\n  return sub_patch_centers_;\n}\n\npy::array_t<int> PyMultipatch::GetInterfaces(const bool recompute) {\n  // check if we should set or get\n  // set\n  if (interfaces_.size() == 0 || recompute) {\n    // get, but need to compute since saved member is empty\n    interfaces_ =\n        InterfacesFromBoundaryCenters(SubPatchCenters(), tolerance_, ParaDim());\n    // Reinit orientations_ as no longer valid\n    interface_orientations_ = py::array_t<int>();\n  }\n\n  // regardless of set/get, it will always return the saved member of\n  // current state\n  return interfaces_;\n}\n\nvoid PyMultipatch::SetInterfaces(const py::array_t<int>& interfaces) {\n  // check if we should set or get\n  // set\n  if (interfaces.size() == 0) {\n    splinepy::utils::PrintAndThrowError("No interface information provided");\n  }\n\n  // size check\n  splinepy::py::CheckPyArrayShape(\n      interfaces,\n      {static_cast<int>(CorePatches().size()),\n       static_cast<int>(CorePatches()[0]->SplinepyParaDim() * 2)},\n      true);\n\n  // Reinit interface_orientations_ as no longer valid\n  interface_orientations_ = py::array_t<int>();\n\n  interfaces_ = interfaces;\n}\n\npy::array_t<int> PyMultipatch::BoundaryPatchIds(const int bid) {\n  // return if it exists\n  if (bid < 0 && boundary_patch_ids_.size() != 0) {\n    return boundary_patch_ids_;\n  }\n\n  // prepare only ingredient - interfaces\n  // negative entries in interfaces mean boundary patch\n  auto interfaces = GetInterfaces(false);\n  const int n_interfaces = interfaces.size();\n  const int* interfaces_ptr = static_cast<int*>(interfaces.request().ptr);\n\n  // create new array\n  py::array_t<int> boundary_patch_ids(n_interfaces);\n  int* boundary_patch_ids_ptr =\n      static_cast<int*>(boundary_patch_ids.request().ptr);\n\n  // add ids of negative interface entries\n  int j{};\n\n  if (bid < 0) {\n    // Extract all boundaries\n    for (int i{}; i < n_interfaces; ++i) {\n      if (interfaces_ptr[i] < 0) {\n        boundary_patch_ids_ptr[j] = i;\n        ++j;\n      }\n    }\n  } else {\n    // Extract specific boundary\n    for (int i{}; i < n_interfaces; ++i) {\n      if (interfaces_ptr[i] == -bid) {\n        boundary_patch_ids_ptr[j] = i;\n        ++j;\n      }\n    }\n  }\n\n  // resize ids\n  boundary_patch_ids.resize({j}, false);\n\n  // Store as default (all)\n  if (bid < 0) {\n    boundary_patch_ids_ = std::move(boundary_patch_ids);\n    return boundary_patch_ids_;\n  }\n\n  return boundary_patch_ids;\n}\n\n/// @brief Gets boundary multi patch\n/// @param bid boundary ID to be extracted\nstd::shared_ptr<PyMultipatch> PyMultipatch::BoundaryMultipatch(const int bid) {\n  // return early if exists\n  if (bid < 0 && boundary_multipatch_) {\n    return boundary_multipatch_;\n  }\n\n  // get boundary_patch_ids;\n  const auto& boundary_pid = BoundaryPatchIds(bid);\n  int* boundary_pid_ptr = static_cast<int*>(boundary_pid.request().ptr);\n  const int n_boundary_pid = boundary_pid.size();\n\n  // values needed for offset\n  const int n_subpatches = ParaDim() * 2;\n\n  // create boundary patches with enough space\n  CoreSplineVector boundary_core_patches(n_boundary_pid);\n\n  // extract patches\n  auto extract_boundaries_step = [&](int, int, const int i_thread) {\n    for (int i{i_thread}; i < n_boundary_pid; i += n_default_threads_) {\n      const auto [i_spline, i_subpatch] =\n          std::div(boundary_pid_ptr[i], n_subpatches);\n      boundary_core_patches[i] =\n          core_patches_[i_spline]->SplinepyExtractBoundary(i_subpatch);\n    }\n  };\n\n  // Execute in parallel\n  splinepy::utils::NThreadExecution(extract_boundaries_step,\n                                    n_boundary_pid,\n                                    n_default_threads_);\n\n  // create return patch\n  std::shared_ptr<PyMultipatch> boundary_multipatch =\n      std::make_shared<PyMultipatch>();\n  boundary_multipatch->patches_ = ToPySplineList(boundary_core_patches);\n  boundary_multipatch->core_patches_ = std::move(boundary_core_patches);\n\n  // Save if all boundaries are stored\n  if (bid < 0) {\n    boundary_multipatch_ = boundary_multipatch;\n  }\n\n  return boundary_multipatch;\n}\n\n/// @brief returns derived class of boundary multi patch\n/// @return\npy::object PyMultipatch::PyBoundaryMultipatch(const int bid) {\n  if (bid < 0) {\n    if (py_boundary_multipatch_.is_none()) {\n      py_boundary_multipatch_ = ToDerived(BoundaryMultipatch(bid));\n    }\n    return py_boundary_multipatch_;\n  } else {\n    return ToDerived(BoundaryMultipatch(bid));\n  }\n}\n\npy::array_t<double> PyMultipatch::Evaluate(py::array_t<double> queries,\n                                           const int nthreads) {\n  // use first spline as dimension guide line\n  const int para_dim = ParaDim();\n  const int dim = Dim();\n\n  // query dim check\n  CheckPyArrayShape(queries, {-1, para_dim}, true);\n\n  // prepare input and output\n  double* queries_ptr = static_cast<double*>(queries.request().ptr);\n  const int n_splines = core_patches_.size();\n  const int n_queries = queries.shape(0);\n  const int n_total = n_splines * n_queries;\n  py::array_t<double> evaluated({n_total, dim});\n  double* evaluated_ptr = static_cast<double*>(evaluated.request().ptr);\n\n  // each thread evaluates similar amount of queries from each spline\n  auto evaluate_step = [&](int, int, const int i_thread) {\n    for (int i{i_thread}; i < n_total; i += nthreads) {\n      const auto [i_spline, i_query] = std::div(i, n_queries);\n      core_patches_[i_spline]->SplinepyEvaluate(\n          &queries_ptr[i_query * para_dim],\n          &evaluated_ptr[(i_spline * n_queries + i_query) * dim]);\n    }\n  };\n\n  // exe\n  splinepy::utils::NThreadExecution(evaluate_step, n_total, nthreads);\n\n  return evaluated;\n}\n\npy::array_t<double> PyMultipatch::Sample(const int resolution,\n                                         const int nthreads,\n                                         const bool same_parametric_bounds) {\n  const int para_dim = ParaDim();\n  const int dim = Dim();\n\n  // n_queries, and n_splines;\n  int n_queries{1};\n  const int n_splines = core_patches_.size();\n\n  // prepare resolutions\n  IntVector resolutions_vector(para_dim);\n  int* resolutions = resolutions_vector.data();\n  for (int i{}; i < para_dim; ++i) {\n    resolutions[i] = resolution;\n    n_queries *= resolution;\n  }\n\n  // prepare input /  output\n  const int n_total = n_splines * n_queries;\n  py::array_t<double> sampled({n_total, dim});\n  double* sampled_ptr = static_cast<double*>(sampled.request().ptr);\n\n  // if you know all the queries have same parametric bounds\n  // you don\'t need to re-compute queries\n  if (same_parametric_bounds) {\n\n    // get para bounds\n    DoubleVector para_bounds_vector(2 * para_dim);\n    double* para_bounds = para_bounds_vector.data();\n    core_patches_[0]->SplinepyParametricBounds(para_bounds);\n\n    // prepare queries\n    DoubleVector queries_vector(n_queries * para_dim);\n    double* queries = queries_vector.data();\n\n    // use grid point generator to fill queries\n    splinepy::utils::GridPoints gp_generator(para_dim,\n                                             para_bounds,\n                                             resolutions);\n    gp_generator.Fill(queries);\n\n    // create lambda for nthread exe\n    auto sample_same_bounds_step = [&](int, int, const int i_thread) {\n      for (int i{i_thread}; i < n_total; i += nthreads) {\n        const auto [i_spline, i_query] = std::div(i, n_queries);\n        core_patches_[i_spline]->SplinepyEvaluate(\n            &queries[i_query * para_dim],\n            &sampled_ptr[(i_spline * n_queries + i_query) * dim]);\n      }\n    };\n\n    splinepy::utils::NThreadExecution(sample_same_bounds_step,\n                                      n_total,\n                                      nthreads);\n\n  } else {\n    // here, we will execute 2 times:\n    //   first, to create grid point helpers for each spline\n    //   second, to sample\n\n    // create a container to hold grid point helper.\n    splinepy::utils::DefaultInitializationVector<splinepy::utils::GridPoints>\n        grid_points(n_splines);\n\n    // create grid_points\n    auto create_grid_points = [&](const int begin, const int end, int) {\n      DoubleVector para_bounds_vector(2 * para_dim);\n      double* para_bounds = para_bounds_vector.data();\n\n      for (int i{begin}; i < end; ++i) {\n        // get para_bounds\n        core_patches_[i]->SplinepyParametricBounds(para_bounds);\n        // setup grid points helper\n        grid_points[i].SetUp(para_dim, para_bounds, resolutions);\n      }\n    };\n\n    // pre compute entries -> this one is a chunk query\n    splinepy::utils::NThreadExecution(create_grid_points, n_splines, nthreads);\n\n    // similar to the one with same_parametric_bounds, except it computes\n    // query on the fly\n    auto sample_step = [&](int, int, const int i_thread) {\n      // each thread needs just one query array\n      DoubleVector thread_query_vector(para_dim);\n      double* thread_query = thread_query_vector.data();\n\n      for (int i{i_thread}; i < n_total; i += nthreads) {\n        const auto [i_spline, i_query] = std::div(i, n_queries);\n        const auto& gp_helper = grid_points[i_spline];\n        gp_helper.IdToGridPoint(i_query, thread_query);\n        core_patches_[i_spline]->SplinepyEvaluate(\n            thread_query,\n            &sampled_ptr[(i_spline * n_queries + i_query) * dim]);\n      }\n    };\n\n    // exe - this one is step\n    splinepy::utils::NThreadExecution(sample_step, n_total, nthreads);\n  }\n\n  return sampled;\n}\n\nvoid PyMultipatch::AddFields(py::list& fields,\n                             const int field_dim,\n                             const bool check_name,\n                             const bool check_dims,\n                             const bool check_degrees,\n                             const bool check_control_mesh_resolutions,\n                             const int nthreads) {\n\n  // allocate space\n  const auto n_current_fields = static_cast<int>(field_multipatches_.size());\n  const auto n_new_fields = static_cast<int>(fields.size());\n\n  // some hint values for null splines\n  const int para_dim = ParaDim();\n\n  // prepare error message\n  std::string field_mismatch_info{};\n  std::mutex field_mismatch_mutex;\n\n  std::vector<std::shared_ptr<PyMultipatch>> field_ptrs(n_new_fields);\n\n  // Multi-threading where each threads deals with a field at a time\n  auto field_to_multipatch = [&](const int begin, const int end, int) {\n    // Chunks over field ids\n    for (int i{begin}; i < end; ++i) {\n      // create multipatch\n      py::list casted_list = fields[i].template cast<py::list>();\n\n      field_ptrs[i] =\n          std::make_shared<PyMultipatch>(casted_list, 1, para_dim, field_dim);\n\n      // propagate same_parametric_bounds_ flag\n      field_ptrs[i]->same_parametric_bounds_ = same_parametric_bounds_;\n\n      try {\n        // check mismatch - doesn\'t check null splines\n        RaiseMismatch(core_patches_,\n                      field_ptrs[i]->core_patches_,\n                      check_name,\n                      check_dims,\n                      field_dim,\n                      check_degrees,\n                      check_control_mesh_resolutions,\n                      1);\n      } catch (const std::runtime_error& e) {\n        // set true, and add error message.\n        std::lock_guard<std::mutex> guard(field_mismatch_mutex);\n        field_mismatch_info += "[mismatch error from the field with index ("\n                               + std::to_string(i) + ")]\\n" + e.what();\n      }\n    }\n  };\n\n  // Execute\n  splinepy::utils::NThreadExecution(field_to_multipatch,\n                                    n_new_fields,\n                                    nthreads);\n\n  // raise, if there were error.\n  if (field_mismatch_info.size() != 0) {\n    splinepy::utils::PrintAndThrowError(field_mismatch_info);\n  }\n\n  py::list local_fields(n_new_fields);\n\n  // turn into a list first to avoid possible runtime memory re-allocation\n  // caused by `append()`\n  for (int i{}; i < n_new_fields; ++i) {\n    local_fields[i] = ToDerived(field_ptrs[i]);\n  }\n\n  // all good, extend to list\n  field_multipatches_ += local_fields;\n}\n\nint PyMultipatch::GetNumberOfControlPoints() {\n  // Init return value\n  int n_control_points{};\n  for (std::size_t i_patch{}; i_patch < core_patches_.size(); i_patch++) {\n    n_control_points += core_patches_[i_patch]->SplinepyNumberOfControlPoints();\n  }\n  return n_control_points;\n}\n\npy::array_t<int> PyMultipatch::GetControlPointOffsets() {\n  // Init return value\n  const int n_core_patches = core_patches_.size();\n  py::array_t<int> control_point_offsets(n_core_patches);\n  int* control_point_offsets_ptr =\n      static_cast<int*>(control_point_offsets.request().ptr);\n  int offset{};\n  for (int i_patch{}; i_patch < n_core_patches; i_patch++) {\n    control_point_offsets_ptr[i_patch] = offset;\n    offset += core_patches_[i_patch]->SplinepyNumberOfControlPoints();\n  }\n  return control_point_offsets;\n}\n\npy::array_t<double> PyMultipatch::GetControlPoints() {\n  // Retrieve number of control points\n  const int& n_control_points = GetNumberOfControlPoints();\n  const py::array_t<int>& control_point_offsets = GetControlPointOffsets();\n  int* control_point_offsets_ptr =\n      static_cast<int*>(control_point_offsets.request().ptr);\n  const int& n_splines = control_point_offsets.size();\n\n  // Init return values\n  py::array_t<double> control_points(n_control_points * Dim());\n  double* control_points_ptr =\n      static_cast<double*>(control_points.request().ptr);\n\n  // Lambda for parallelization\n  const int& dim = Dim();\n  auto copy_control_points = [&](const int start, const int end, int) {\n    for (int i{start}; i < end; ++i) {\n      core_patches_[i]->SplinepyCurrentProperties(\n          nullptr,\n          nullptr,\n          &control_points_ptr[control_point_offsets_ptr[i] * dim],\n          nullptr);\n    }\n  };\n\n  // Execute with lambda\n  splinepy::utils::NThreadExecution(copy_control_points,\n                                    n_splines,\n                                    n_default_threads_);\n\n  // Return control points\n  control_points.resize({n_control_points, dim});\n  return control_points;\n}\n\npy::object ToDerived(std::shared_ptr<PyMultipatch> core_obj) {\n  const auto to_derived = py::module_::import("splinepy").attr("to_derived");\n  return to_derived(py::cast(core_obj));\n}\n\n/// @brief Add multi patch.\n/// Returns [connectivity, vertex_ids, edge_information, boundaries]\n/// @param m\nvoid init_multipatch(py::module_& m) {\n  m.def("interfaces_from_boundary_centers",\n        &splinepy::py::InterfacesFromBoundaryCenters,\n        py::arg("face_center_vertices"),\n        py::arg("tolerance"),\n        py::arg("para_dim"));\n  m.def("extract_all_boundary_splines",\n        &splinepy::py::ExtractAllBoundarySplines,\n        py::arg("splines"),\n        py::arg("interfaces"),\n        py::arg("nthreads") = 1);\n  m.def("boundaries_from_continuity",\n        &splinepy::py::AddBoundariesFromContinuity,\n        py::arg("boundary_splines"),\n        py::arg("boundary_interfaces"),\n        py::arg("global_interfaces"),\n        py::arg("tolerance"),\n        py::arg("nthreads") = 1);\n\n  py::class_<splinepy::py::PyMultipatch,\n             std::shared_ptr<splinepy::py::PyMultipatch>>\n      klasse(m, "PyMultipatch");\n\n  klasse.def(py::init<>())\n      .def(py::init<py::list&, const int, const bool>())\n      .def(py::init<std::shared_ptr<PyMultipatch>&>()) // for to_derived()\n      .def_readwrite("n_default_threads", &PyMultipatch::n_default_threads_)\n      .def_readwrite("same_parametric_bounds",\n                     &PyMultipatch::same_parametric_bounds_)\n      .def_readwrite("tolerance", &PyMultipatch::tolerance_)\n      .def("clear", &PyMultipatch::Clear)\n      .def_property_readonly("para_dim", &PyMultipatch::ParaDim)\n      .def_property_readonly("dim", &PyMultipatch::Dim)\n      .def_property_readonly("name", &PyMultipatch::Name)\n      .def_property_readonly("whatami", &PyMultipatch::WhatAmI)\n      .def_property_readonly("control_points", &PyMultipatch::GetControlPoints)\n      .def("control_point_offsets", &PyMultipatch::GetControlPointOffsets)\n      .def_property("patches",\n                    &PyMultipatch::GetPatches,\n                    &PyMultipatch::SetPatchesDefault)\n      .def("sub_multipatch", &PyMultipatch::PySubMultipatch)\n      .def("sub_patch_centers", &PyMultipatch::SubPatchCenters)\n      .def("get_interfaces",\n           &PyMultipatch::GetInterfaces,\n           py::arg("recompute") = false)\n      .def("set_interfaces",\n           &PyMultipatch::SetInterfaces,\n           py::arg("interfaces"))\n      .def("boundary_patch_ids",\n           &PyMultipatch::BoundaryPatchIds,\n           py::arg("bid") = -1)\n      .def("boundary_multipatch",\n           &PyMultipatch::PyBoundaryMultipatch,\n           py::arg("bid") = -1)\n      .def("evaluate",\n           &PyMultipatch::Evaluate,\n           py::arg("queries"),\n           py::arg("nthreads"))\n      .def("sample",\n           &PyMultipatch::Sample,\n           py::arg("resolution"),\n           py::arg("nthreads"),\n           py::arg("same_parametric_bounds"))\n      .def("add_fields",\n           &PyMultipatch::AddFields,\n           py::arg("fields"),\n           py::arg("field_dim"),\n           py::arg("check_name"),\n           py::arg("check_dims"),\n           py::arg("check_degrees"),\n           py::arg("checK_control_mesh_resolutions"),\n           py::arg("nthreads"))\n      .def("fields", &PyMultipatch::GetFields)\n      .def("interface_orientations",\n           &PyMultipatch::GetInterfaceOrientations,\n           py::arg("tolerance"),\n           py::arg("nthreads") = 1)\n      //.def("", &PyMultipatch::)\n      ;\n}\n\n} // namespace splinepy::py\n',
        }
